const assert = require("node:assert");
const fs = require("node:fs");
const path = require("node:path");

let passed = 0;
let failed = 0;

function test(name, fn) {
  try {
    fn();
    passed++;
    console.log(`  ✅ ${name}`);
  } catch (e) {
    failed++;
    console.log(`  ❌ ${name}: ${e.message}`);
  }
}

// ─── Load catalog fixture ──────────────────────────────────────────────────

function loadCatalog() {
  const root = findArayaRoot();
  const catalogPath = path.resolve(root, ".araya", "catalog", "catalog.json");
  if (!fs.existsSync(catalogPath)) {
    throw new Error(`Catalog not found: ${catalogPath}`);
  }
  return JSON.parse(fs.readFileSync(catalogPath, "utf-8"));
}

function findArayaRoot() {
  let dir = __dirname;
  for (let i = 0; i < 15; i++) {
    if (fs.existsSync(path.resolve(dir, "araya.yaml"))) return dir;
    const parent = path.resolve(dir, "..");
    if (parent === dir) break;
    dir = parent;
  }
  throw new Error("Cannot find araya.yaml root");
}

// ─── Helper: Levenshtein distance ──────────────────────────────────────────

function levenshtein(a, b) {
  const m = a.length, n = b.length;
  const dp = Array.from({ length: m + 1 }, (_, i) => [i]);
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] = a[i - 1] === b[j - 1]
        ? dp[i - 1][j - 1]
        : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
    }
  }
  return dp[m][n];
}

function findSimilar(query, candidates, maxDistance = 5, maxResults = 3) {
  return candidates
    .map(c => ({ name: c, distance: levenshtein(query.toLowerCase(), c.toLowerCase()) }))
    .filter(e => e.distance <= maxDistance)
    .sort((a, b) => a.distance - b.distance)
    .slice(0, maxResults)
    .map(e => e.name);
}

