// AC-7: Función inexistente devuelve error claro + sugerencias reales
// ═══════════════════════════════════════════════════════════════════════════

console.log("\n── AC-7: Función inexistente → error claro + sugerencias reales ──");

// Build lookup sets for fuzzy matching
const allNames = [
  ...catalog.commands.map(c => c.slash_command),
  ...catalog.agents.map(a => a.name),
  ...catalog.skills.map(s => s.name),
];

test("AC-7.1: query 'invento-que-no-existe' returns no exact match", () => {
  const query = "invento-que-no-existe";
  const exactMatch = allNames.find(n => n.toLowerCase() === query.toLowerCase());
  assert.equal(exactMatch, undefined, `Unexpected exact match for nonsense query: ${exactMatch}`);
});

test("AC-7.2: fuzzy suggestions for 'invento-que-no-existe' are empty (Levenshtein > 5)", () => {
  const suggestions = findSimilar("invento-que-no-existe", allNames, 5, 3);
  assert.equal(suggestions.length, 0,
    `Should have 0 suggestions for distant query, got: ${suggestions.join(", ")}`);
});

test("AC-7.3: typo 'uat-genrate' suggests 'uat-generate'", () => {
  const suggestions = findSimilar("uat-genrate", allNames, 5, 3);
  assert.ok(suggestions.includes("uat-generate"),
    `Typo 'uat-genrate' should suggest uat-generate, got: ${suggestions.join(", ")}`);
});

test("AC-7.4: typo 'sonai' suggests 'sonia'", () => {
  const suggestions = findSimilar("sonai", allNames, 5, 3);
  assert.ok(suggestions.includes("sonia"),
    `Typo 'sonai' should suggest sonia, got: ${suggestions.join(", ")}`);
});

test("AC-7.5: typo '/araya:staus' suggests '/araya:status'", () => {
  const suggestions = findSimilar("/araya:staus", allNames, 5, 3);
  assert.ok(suggestions.includes("/araya:status"),
    `Typo '/araya:staus' should suggest /araya:status, got: ${suggestions.join(", ")}`);
});

test("AC-7.6: fuzzy suggestions never include invented names", () => {
  // All suggestions must be real names from the catalog
  for (const query of ["uat-genrate", "sonai", "/araya:staus", "valentna"]) {
    const suggestions = findSimilar(query, allNames, 5, 3);
    for (const s of suggestions) {
      assert.ok(allNames.includes(s),
        `Suggestion "${s}" for query "${query}" is not in catalog`);
    }
  }
});

test("AC-7.7: distant query 'zzzznotclose' returns no suggestions", () => {
  const suggestions = findSimilar("zzzznotclose", allNames, 5, 3);
  assert.equal(suggestions.length, 0,
    `Should have 0 suggestions, got: ${suggestions.join(", ")}`);
});

test("AC-7.8: suggestions are limited to max 3", () => {
  // Use a query close to many things
  const suggestions = findSimilar("test", allNames, 10, 99);
  // With Levenshtein ≤ 5 we get a reasonable number; verify no explosion
  const suggestions5 = findSimilar("test", allNames, 5, 99);
  assert.ok(suggestions5.length <= 30,
    `Too many fuzzy matches for 'test': ${suggestions5.length}`);
});

// ═══════════════════════════════════════════════════════════════════════════
// AC-8: Búsqueda por keywords, dominio, agente, skill
// ═══════════════════════════════════════════════════════════════════════════

console.log("\n── AC-8: Búsqueda por keywords, dominio, agente, skill ──");

function searchByKeyword(keyword) {
  const results = [];
  const lower = keyword.toLowerCase();

  for (const cmd of catalog.commands) {
    if (cmd.name.toLowerCase().includes(lower) ||
        (cmd.short_help && cmd.short_help.toLowerCase().includes(lower)) ||
        (cmd.keywords && cmd.keywords.some(k => k.toLowerCase().includes(lower)))) {
      results.push({ type: "command", name: cmd.slash_command, entry: cmd });
    }
  }
  for (const agent of catalog.agents) {
    if (agent.name.toLowerCase().includes(lower) ||
        agent.role.toLowerCase().includes(lower) ||
        (agent.keywords && agent.keywords.some(k => k.toLowerCase().includes(lower)))) {
      results.push({ type: "agent", name: agent.name, entry: agent });
    }
  }
  for (const skill of catalog.skills) {
    if (skill.name.toLowerCase().includes(lower) ||
        (skill.purpose && skill.purpose.toLowerCase().includes(lower)) ||
        (skill.keywords && skill.keywords.some(k => k.toLowerCase().includes(lower)))) {
      results.push({ type: "skill", name: skill.name, entry: skill });
    }
  }
  return results;
}

function searchByDomain(domain) {
  const results = [];
  const lower = domain.toLowerCase();

  for (const cmd of catalog.commands) {
    if (cmd.domain && cmd.domain.toLowerCase().includes(lower)) {
      results.push({ type: "command", name: cmd.slash_command, domain: cmd.domain });
    }
  }
  for (const agent of catalog.agents) {
    if (agent.domain && agent.domain.toLowerCase().includes(lower)) {
      results.push({ type: "agent", name: agent.name, domain: agent.domain });
    }
  }
  for (const skill of catalog.skills) {
    if (skill.domain && skill.domain.toLowerCase().includes(lower)) {
      results.push({ type: "skill", name: skill.name, domain: skill.domain });
    }
  }
  return results;
}

function searchByAgent(agentName) {
  const agent = catalog.agents.find(a => a.name.toLowerCase() === agentName.toLowerCase());
  if (!agent) return [];
  return agent.skills.map(s => catalog.skills.find(sk => sk.name === s)).filter(Boolean);
}

test("AC-8.1: keyword 'uat' finds ≥ 5 results", () => {
  const results = searchByKeyword("uat");
  assert.ok(results.length >= 5,
    `Search for 'uat' should find ≥ 5 results, got ${results.length}`);
});

test("AC-8.2: keyword 'uat' finds uat-generate and uat-review skills", () => {
  const results = searchByKeyword("uat");
  const skillNames = results.filter(r => r.type === "skill").map(r => r.name);
  assert.ok(skillNames.includes("uat-generate"), "Should find uat-generate");
  assert.ok(skillNames.includes("uat-review"), "Should find uat-review");
});

test("AC-8.3: keyword 'uat' finds /araya:generate-uat and /araya:review-uat commands", () => {
  const results = searchByKeyword("uat");
  const cmdNames = results.filter(r => r.type === "command").map(r => r.name);
  assert.ok(cmdNames.includes("/araya:generate-uat"), "Should find /araya:generate-uat");
  assert.ok(cmdNames.includes("/araya:review-uat"), "Should find /araya:review-uat");
});

test("AC-8.4: domain 'security' finds diana agent", () => {
  const results = searchByDomain("security");
  const agentNames = results.filter(r => r.type === "agent").map(r => r.name);
  assert.ok(agentNames.includes("diana"),
    `Domain security should find diana, got agents: ${agentNames.join(", ")}`);
});

test("AC-8.5: domain 'security' finds security skills", () => {
  const results = searchByDomain("security");
  const skillNames = results.filter(r => r.type === "skill").map(r => r.name);
  const expected = ["threat-model", "secure-arch", "secure-code", "pentest", "compliance", "secrets"];
  for (const name of expected) {
    assert.ok(skillNames.includes(name),
      `Domain security should find skill ${name}`);
  }
});

test("AC-8.6: domain 'security' should NOT include non-security skills", () => {
  const results = searchByDomain("security");
  const skillNames = results.filter(r => r.type === "skill").map(r => r.name);
  assert.ok(!skillNames.includes("component"), "Domain security should NOT include component");
  assert.ok(!skillNames.includes("api-design"), "Domain security should NOT include api-design");
});

test("AC-8.7: search by agent 'mateo' returns only his skills", () => {
  const skills = searchByAgent("mateo");
  const names = skills.map(s => s.name);
  assert.ok(names.includes("cost-analysis"), "mateo should have cost-analysis");
  assert.ok(names.includes("usage-metering"), "mateo should have usage-metering");
  assert.ok(names.includes("resource-rightsizing"), "mateo should have resource-rightsizing");
  assert.ok(names.includes("budget-forecasting"), "mateo should have budget-forecasting");
  assert.ok(names.includes("token-efficiency"), "mateo should have token-efficiency");
});

test("AC-8.8: search by agent 'mateo' returns exactly his assigned skills", () => {
  const agent = catalog.agents.find(a => a.name === "mateo");
  const skills = searchByAgent("mateo");
  assert.equal(skills.length, agent.skill_count,
    `mateo skill count mismatch: search ${skills.length} vs catalog ${agent.skill_count}`);
});

test("AC-8.9: keyword search is case-insensitive", () => {
  const lower = searchByKeyword("uat");
  const upper = searchByKeyword("UAT");
  assert.equal(lower.length, upper.length, "Case-insensitive search should match");
});

test("AC-8.10: keyword 'nonexistent-xyz-999' returns 0 results", () => {
  const results = searchByKeyword("nonexistent-xyz-999");
  assert.equal(results.length, 0, "Nonsense keyword should return 0 results");
});

